@typeparam TItem

@if (_items is not null)
{
    @for (int i = 0; i < _items.Count; i++)
    {
        var index = i;
        <div class="sortable-list-item">
            <div class="sortable-list-item-content">
                @ItemTemplate(_items[index])
            </div>
            <div class="sortable-list-item-actions">
                <button type="button" disabled="@(index == 0)" @onclick="() => MoveUp(index)">Move Up</button>
                <button type="button" disabled="@(index == _items.Count - 1)" @onclick="() => MoveDown(index)">Move Down</button>
            </div>
        </div>
    }
}

using Microsoft.AspNetCore.Components;

public partial class SortableList<TItem>
{
    private List<TItem> _items = new();

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = default!;

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ItemTemplate { get; set; } = default!;

    [Parameter]
    public EventCallback<IReadOnlyList<TItem>> OnOrderChanged { get; set; }

    public override Task SetParametersAsync(ParameterView parameters)
    {
        if (parameters.TryGetValue<IReadOnlyList<TItem>>(nameof(Items), out var incoming)
            && !ReferenceEquals(incoming, Items))
        {
            _items = new List<TItem>(incoming);
        }

        return base.SetParametersAsync(parameters);
    }

    private async Task MoveUp(int index)
    {
        if (index <= 0)
            return;

        (_items[index - 1], _items[index]) = (_items[index], _items[index - 1]);
        await NotifyChanged();
    }

    private async Task MoveDown(int index)
    {
        if (index >= _items.Count - 1)
            return;

        (_items[index], _items[index + 1]) = (_items[index + 1], _items[index]);
        await NotifyChanged();
    }

    private async Task NotifyChanged()
    {
        if (OnOrderChanged.HasDelegate)
        {
            await OnOrderChanged.InvokeAsync(_items.AsReadOnly());
        }
    }
}

